#include "interface.h"
#include <cuda_runtime.h>

namespace {
__global__ void reduce_kernel(const int* input, int* output, int n) {
    extern __shared__ int sdata[];
    unsigned int tid = threadIdx.x;
    unsigned int i = blockIdx.x * (blockDim.x * 2) + threadIdx.x;

    int sum = 0;
    if (i < n) sum = input[i];
    if (i + blockDim.x < n) sum += input[i + blockDim.x];

    sdata[tid] = sum;
    __syncthreads();

    for (unsigned int s = blockDim.x / 2; s > 32; s >>= 1) {
        if (tid < s) sdata[tid] += sdata[tid + s];
        __syncthreads();
    }

    if (tid < 32) {
        volatile int* v = sdata;
        if (blockDim.x >= 64) v[tid] += v[tid + 32];
        for (int offset = 16; offset > 0; offset >>= 1)
            v[tid] += __shfl_down_sync(0xffffffff, v[tid], offset);

        if (tid == 0) atomicAdd(output, v[0]);
    }
}
} // namespace

void add_reduce_i32(const int* input, int* output, int n, int iters) {
    const int threads = 256;
    const int blocks = (n + (threads * 2) - 1) / (threads * 2);
    for (int iter = 0; iter < iters; ++iter) {
        cudaMemset(output, 0, sizeof(int));
        reduce_kernel<<<blocks, threads, threads * sizeof(int)>>>(input, output, n);
    }
}
